public:
    RangeModule() {

    }

    void addRange(int left, int right) {
        auto it = ranges.lower_bound(left);
        if (it != ranges.begin()) {
            --it;
            if (it->second >= left) {
                left = it->first;
                right = max(right, it->second);
                it = ranges.erase(it);
            } else {
                ++it;
            }
        }
        while (it != ranges.end() && it->first <= right) {
            right = max(right, it->second);
            it = ranges.erase(it);
        }
        ranges[left] = right;
    }

    bool queryRange(int left, int right) {
        auto it = ranges.upper_bound(left);
        if (it == ranges.begin() || (--it)->second < right) {
            return false;
        }
        return true;
    }

    void removeRange(int left, int right) {
        auto it = ranges.lower_bound(left);
        if (it != ranges.begin()) {
            --it;
            if (it->second > left) {
                int originalRight = it->second;
                it->second = left;
                if (originalRight > right) {
                    ranges[right] = originalRight;
                }
                ++it;
            } else {
                ++it;
            }
        }
        while (it != ranges.end() && it->first < right) {
            if (it->second > right) {
                ranges[right] = it->second;
            }
            it = ranges.erase(it);
        }
    }
private:
    map<int, int> ranges;
};

